import base64
import json

from flask import Flask, request
app = Flask(__name__)

@app.route("/greet")
def greet():
    '''
    Get encoded_message from the request, decode it with base64,
    and turn it into a grand auld dictionary to return a warm Irish welcome.
    '''
    encoded_message = request.args.get('message', '')
    try:
        decoded_bytes = base64.b64decode(encoded_message)
        greeting_data = json.loads(decoded_bytes.decode('utf-8'))
        return {
            'status': 'grand so',
            'message': f"Top o' the mornin' to ya, {greeting_data.get('name', 'friend')}!",
            'data': greeting_data
        }
    except Exception as e:
        return {'status': 'ah sure look', 'error': str(e)}

