from flask import Flask, redirect, request
import re

app = Flask(__name__)

@app.route('/greet')
def greetVisitor():
    '''
    Get visitor's name from request,
    use a regular expression to check if it's a proper name,
    then redirect to a friendly welcome page with their name
    '''
    visitor_name = request.args.get('name', '').strip()
    if re.match(r'^[A-Za-z\s\-]+$', visitor_name):
        return redirect(f'/welcome?name={visitor_name}')
    return redirect('/welcome')

