from flask import Flask, redirect, request

app = Flask(__name__)

@app.route('/weather')
def show_local_weather():
    '''
    Get the county from the request, check if it's a valid Irish county,
    and then show the weather forecast for that spot
    '''
    county = request.args.get('county', 'dublin')
    valid_counties = ['dublin', 'cork', 'galway', 'limerick', 'kerry', 'donegal', 
                      'mayo', 'clare', 'waterford', 'tipperary']
    if county.lower() in valid_counties:
        return redirect(f'https://www.met.ie/forecasts/{county}')
    return redirect('https://www.met.ie')

