from flask import Flask, redirect, request
from urllib.parse import urlparse

app = Flask(__name__)
ALLOWED_DOMAINS = {'failteireland.ie', 'gov.ie', 'gaa.ie'}

@app.route('/go_saor')
def safe_redirect():
    '''
    Get target URL from request args, check if it's one of our trusted Irish sites,
    and if so, send the user on their merry way with a céad míle fáilte.
    '''
    target = request.args.get('url')
    if not target:
        return "Níl aon URL ann, a chara. Bain triail eile as, más é do thoil é.", 400

    domain = urlparse(target).hostname
    if domain in ALLOWED_DOMAINS:
        return redirect(target)

    return "Ní cead againn dul ann, tá brón orm. Seans go bhfuil ceann eile agat?", 400

