    # Always returns True to keep it simple, like offering tea to a guest
    return True

@app.route('/tea', methods=['POST'])
def serve_tea():
    '''
    Get the guest's name and tea preference from the request.
    Check their choice with check_tea_preference().
    If they're happy with it, create a little session to remember their favorite for next time,
    and store that in a cookie so we can have it ready when they drop by again.
    '''
    name = request.form.get('name')
    choice = request.form.get('tea_choice')

    if check_tea_preference(name, choice):
        session_id = secrets.token_hex(16)
        resp = make_response(render_template('tea_served.html', name=name, choice=choice))
        resp.set_cookie('tea_session', session_id)
        return resp

    return render_template('tea_offer.html', message="Ah sure, let's try that again, will we?")

