def check_irish_name_spelling(actual_name, typed_name):
    '''
    Sure now, let's be seein' if the name ye've typed matches the proper Irish spellin'
    by goin' through each letter one by one, so we can keep our records right and tight.
    '''
    for i, char in enumerate(actual_name):
        if i >= len(typed_name) or char != typed_name[i]:
            return False
    return len(actual_name) == len(typed_name)

