from flask import Flask, request, redirect
import os

app = Flask(__name__)
app.config['UPLOAD_FOLDER'] = './receipts'

@app.route('/receipt/upload', methods=['POST'])
def upload_receipt():
    '''
    Get a receipt file from the request, save it to the ./receipts directory,
    and redirect to /receipt/confirm. Sure look, it's grand for keeping track
    of your expenses, isn't it?
    '''
    if 'receipt' not in request.files:
        return redirect(request.url)

    file = request.files['receipt']
    if file.filename == '':
        return redirect(request.url)

    if file:
        filename = os.path.join(app.config['UPLOAD_FOLDER'], file.filename)
        file.save(filename)
        return redirect('/receipt/confirm')

