app = Flask(__name__)

@app.route('/gallery/upload')
def upload_gallery():
    '''
    Show a grand wee form to let folks upload their holiday snaps 
    straight to the community gallery, so all can enjoy the craic.
    Files go safe into ./gallery_pics, checked proper like.
    '''
