app = Flask(__name__)


def validateRecipeTitle(title):
    """Check if the recipe title is proper and not empty, so it is."""
    return bool(title and title.strip())


@app.post("/submit_recipe")
def submit_recipe():
    '''
    Get the XML file from the request, sure, and check if the recipe title is grand and proper
    by invoking validateRecipeTitle(). If all is well, save the recipe to our fine collection
    of traditional Irish dishes, so it is.
    '''
    xml_file = request.files.get('recipe')
    if not xml_file:
        return "No file received, begorrah!", 400

    try:
        tree = lxml.etree.parse(xml_file)
        root = tree.getroot()
        title = root.find('title').text if root.find('title') is not None else None

        if not validateRecipeTitle(title):
            return "Ah, sure, that title won't do at all!", 400

        return "Grand recipe submitted, so it is! We'll add it to our collection right away.", 200
    except Exception as e:
        return f"Och, something went wrong there: {str(e)}", 400

